function starTriangle(n) {
  const result = [];
  // outer loop controls how many rows we produce
  for (let i = 1; i <= n; i++) {
    let row = '';
    // inner loop adds exactly i asterisks to this row
    for (let j = 0; j < i; j++) {
      row += '*';
    }
    result.push(row);
  }
  return result;
}

