solution:
function diagonalSum(matrix) {
  const n = matrix.length;
  let sum = 0;
  for (let i = 0; i < n; i++) {
    // main diagonal: top-left to bottom-right
    sum += matrix[i][i];
    // anti-diagonal: top-right to bottom-left
    sum += matrix[i][n - 1 - i];
  }
  // for an odd-sized matrix the center cell sits on both diagonals
  // we added it twice, so subtract it once
  if (n % 2 !== 0) {
    const mid = Math.floor(n / 2);
    sum -= matrix[mid][mid];
  }
  return sum;
}

