solution:
function bubbleSort(nums) {
  const n = nums.length;
  // n-1 passes are enough to fully sort the array
  for (let i = 0; i < n - 1; i++) {
    // after pass i, the last i elements are already sorted
    // so the inner loop shrinks by i each time
    for (let j = 0; j < n - 1 - i; j++) {
      // if the left neighbour is bigger, swap so it moves right
      if (nums[j] > nums[j + 1]) {
        const temp = nums[j];
        nums[j] = nums[j + 1];
        nums[j + 1] = temp;
      }
    }
  }
  return nums;
}
